def cat_score(tests, cat_prefix, target=10):
    """Score 1-10 from passes vs warnings vs fails inside a category."""
    rel = [t for t in tests if t[1].startswith(cat_prefix)]
    if not rel:
        return "—"
    passes = sum(1 for t in rel if t[3] in ("pass",))
    warns = sum(1 for t in rel if t[3] in ("warn", "warning", "partial", "info"))
    fails = sum(1 for t in rel if t[3] in ("fail",))
    raw = (passes + 0.5 * warns) / len(rel) * 10
    return round(raw, 1)


def aggregate(tests):
    cats = {
        "First Impressions":          cat_score(tests, "First Impressions"),
        "Accessibility":              cat_score(tests, "Accessibility"),
        "Forms & Inputs":             cat_score(tests, "Forms & Inputs"),
        "Navigation & IA":            cat_score(tests, "Navigation & IA"),
        "Performance & Loading":      cat_score(tests, "Performance & Loading"),
        "Mobile Responsiveness":      cat_score(tests, "Mobile Responsiveness"),
        "Content Quality":            cat_score(tests, "Content Quality"),
        "Backend Integration":        cat_score(tests, "Backend Integration"),
    }
    numerics = [v for v in cats.values() if isinstance(v, (int, float))]
    cats["Aggregate"] = round(sum(numerics) / len(numerics), 2) if numerics else "—"
    return cats


WAO_SCORES = aggregate(WAO_TESTS)
KAI_SCORES = aggregate(KA_TESTS)
FUM_SCORES = aggregate(FM_TESTS)


# Instrumentl gap coverage (43 tests)
def ic_coverage(tests):
    rel = [t for t in tests if t[0].startswith("FM-IC-")]
    p = sum(1 for t in rel if t[3] == "pass")
    pt = sum(1 for t in rel if t[3] == "partial")
    f = sum(1 for t in rel if t[3] == "fail")
    return p, pt, f, len(rel)


IC_PASS, IC_PARTIAL, IC_FAIL, IC_TOTAL = ic_coverage(FM_TESTS)


